// Обработка результатов RapidAPI и фильтрация по критериям
const items = $input.item.json.result?.products || [];
const minRating = $node["Установить параметры поиска"].json.min_rating;
const minReviews = $node["Установить параметры поиска"].json.min_reviews;
const minPrice = $node["Установить параметры поиска"].json.min_price;
const maxPrice = $node["Установить параметры поиска"].json.max_price;

const filteredProducts = items
  .filter(item => {
    const rating = parseFloat(item.averageStarRate || 0);
    const reviews = parseInt(item.tradeCount || 0);
    const price = parseFloat(item.minPrice?.value || 0);

    return (
      rating >= minRating &&
      reviews >= minReviews &&
      price >= minPrice &&
      price <= maxPrice
    );
  })
  .map(item => ({
    product_id: `scout_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    timestamp: new Date().toISOString(),
    name: item.productTitle,
    price_aliexpress: parseFloat(item.minPrice?.value || 0),
    rating: parseFloat(item.averageStarRate || 0),
    reviews_count: parseInt(item.tradeCount || 0),
    url: item.productDetailUrl,
    thumbnail: item.imageUrl,
    category: $json.search_query,
    validation_layer_1: 'PASS'
  }));

return filteredProducts.map(product => ({ json: product }));

// Парсинг Google Trends данных
const rawData = $input.item.json.body || '{}';

// Убираем первую строку (защита от парсинга)
const jsonData = rawData.replace(/^\)\]}'/, '');

let trendScore = 0;
try {
  const data = JSON.parse(jsonData);
  const timeline = data.default?.timelineData || [];

  if (timeline.length > 0) {
    // Берем последние 12 недель
    const recentData = timeline.slice(-12);
    const values = recentData.map(d => d.value?.[0] || 0);
    const average = values.reduce((a, b) => a + b, 0) / values.length;

    // Проверяем рост тренда
    const firstHalf = values.slice(0, 6).reduce((a, b) => a + b, 0) / 6;
    const secondHalf = values.slice(6).reduce((a, b) => a + b, 0) / 6;
    const growth = ((secondHalf - firstHalf) / firstHalf) * 100;

    trendScore = Math.round(average);
  }
} catch (e) {
  trendScore = 0;
}

return {
  json: {
    ...($node["Фильтр: Слой 1 (Базовая валидация)"].json),
    google_trends_score: trendScore,
    trend_direction: trendScore > 50 ? 'rising' : 'stable',
    validation_layer_4: trendScore > 30 ? 'PASS' : 'FAIL'
  }
};

