// Объединяем все данные и создаем финальный отчет
const product = $node["Анализ: Слой 4 (Google Trends)"].json;
const gptAnalysis = JSON.parse($input.item.json.response || '{}');

// Расчет юнит-экономики
const cost = product.price_aliexpress;
const shipping = 3;
const packaging = 1;
const totalCost = cost + shipping + packaging;

const suggestedPrice = Math.round(totalCost * 3.5); // 3.5x маржа
const shopifyFee = suggestedPrice * 0.02;
const paymentFee = suggestedPrice * 0.03;
const adCost = suggestedPrice * 0.3; // 30% на рекламу

const profit = suggestedPrice - totalCost - shopifyFee - paymentFee - adCost;
const margin = (profit / suggestedPrice) * 100;
const roi = (profit / totalCost) * 100;

const finalScore = (
  (product.rating / 5) * 10 + // 10 баллов макс
  (Math.min(product.reviews_count / 100, 10)) + // 10 баллов макс
  (product.google_trends_score / 10) + // 10 баллов макс
  (gptAnalysis.total || 5) // 10 баллов макс из GPT
) / 4;

const recommendation = 
  finalScore >= 8 && margin >= 25 && roi >= 80 ? 'STRONG BUY' :
  finalScore >= 6 && margin >= 20 && roi >= 60 ? 'BUY' :
  finalScore >= 5 ? 'MAYBE' : 'PASS';

return {
  json: {
    product_id: product.product_id,
    timestamp: product.timestamp,
    product_info: {
      name: product.name,
      category: product.category,
      aliexpress_url: product.url,
      price_aliexpress: product.price_aliexpress,
      rating: product.rating,
      reviews_count: product.reviews_count,
      thumbnail: product.thumbnail
    },
    trend_analysis: {
      google_trends_score: product.google_trends_score,
      trend_direction: product.trend_direction
    },
    economics: {
      cost: totalCost.toFixed(2),
      suggested_price: suggestedPrice,
      profit_per_unit: profit.toFixed(2),
      margin_percent: margin.toFixed(1),
      roi_percent: roi.toFixed(1)
    },
    creative_analysis: gptAnalysis,
    validation_score: {
      layer_1_screening: product.validation_layer_1,
      layer_4_google_trends: product.validation_layer_4,
      overall_score: finalScore.toFixed(1),
      recommendation: recommendation
    },
    next_steps: [
      margin >= 25 ? 'Заказать sample для тестирования' : 'Пересмотреть ценообразование',
      'Найти поставщика на Alibaba',
      'Подготовить креативы для тестовой кампании'
    ]
  }
};

